const now = new Date();
const today = now.toISOString().slice(0, 10);
const sevenDaysAgo = new Date(now - 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
const currentMonth = now.toISOString().slice(0, 7);

// ── PAYCHECK DETECTION ────────────────────────────────────────────────────────
// The workflow looks for a deposit in your checking account this week that
// matches your expected paycheck amount (within tolerance).
// Run Workflow 00 to get your checkingAccountId.
//
// expectedPaycheck:   your typical net (take-home) paycheck amount
// paycheckTolerance:  how many dollars off it can be and still count
//                     (covers tax adjustments, benefit changes, etc.)

return [{
  json: {
    bridgeUrl:        'http://actual-bridge:3788',
    telegramChatId:   'REPLACE_WITH_YOUR_TELEGRAM_CHAT_ID',
    checkingAccountId: 'GET_FROM_WF00',  // your primary checking account ID
    expectedPaycheck:  0,     // REPLACE: your typical net paycheck amount
    paycheckTolerance: 200,   // dollars of wiggle room (adjust up if deductions vary)
    today,
    sevenDaysAgo,
    currentMonth,
  }
}];

const config       = $('Config').item.json;
const txRes        = $('Get Checking Transactions').item.json;
const monthRes     = $('Get Month Budget').item.json;
const transactions = txRes.data || [];
const groups       = monthRes.data?.categoryGroups || [];

// ── Paycheck detection ────────────────────────────────────────────────────────
const paycheckCents  = config.expectedPaycheck * 100;
const toleranceCents = config.paycheckTolerance * 100;
const paycheckTx = transactions.find(t =>
  t.amount > 0 && Math.abs(t.amount - paycheckCents) <= toleranceCents
);
const paycheckAmount = paycheckTx ? paycheckTx.amount / 100 : 0;
const paycheckFound  = !!paycheckTx;

// ── Build message ─────────────────────────────────────────────────────────────
const date = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });
let msg = 'FRIDAY PAYCHECK UPDATE - ' + date + '\n\n';

if (paycheckFound) {
  msg += 'Paycheck received: $' + paycheckAmount.toFixed(2) + '\n';
} else {
  msg += 'No paycheck detected this week\n';
  msg += '(expected ~$' + config.expectedPaycheck.toFixed(2) + ' — check manually)\n';
}
msg += '\n';

// ── Budget snapshot for the month ─────────────────────────────────────────────
let budgetLines = '';
for (const group of groups) {
  const groupSpent  = (group.categories || []).reduce((s, c) => s + (c.spent  || 0), 0) / 100;
  const groupBudget = (group.categories || []).reduce((s, c) => s + (c.budgeted || 0), 0) / 100;
  if (groupBudget > 0) {
    const pct = ((groupSpent / groupBudget) * 100).toFixed(0);
    budgetLines += group.name + ': $' + groupSpent.toFixed(0) + ' / $' + groupBudget.toFixed(0) + ' (' + pct + '%)\n';
  }
}
if (budgetLines) {
  msg += 'Month-to-date budget:\n' + budgetLines;
}

msg += '\nRemember to categorize any uncategorized transactions in Actual.';
return [{ json: { ...config, telegramMessage: msg } }];
